```class Solution {
public:
    vector<vector<int>> combine(int n, int k) {
        vector<vector<int>> result;
        dfs(result, n, k, vector<int>(), 1, 0);
        return result;
    }

    void dfs(vector<vector<int>> result, int n, int k, vector<int> curr, int start, int count) {
        if (count == k) {
            result.push_back(curr);
            return;
        }

        for (int i = start; i <= n; i++) {
            curr.push_back(i);
            dfs(result, n, k, curr, i + 1, count + 1);
            curr.pop_back();
        }
    }
};```

